var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"다들 잘 접속했나……?","JPN":"みんな無事アクセスできた……？","ENG":"Is everyone online...?","TWN":"大家都順利登入了嗎……？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"음…… 초등부부터 고등부까지…… 잘 모였네.","JPN":"ん……初等部から高等部まで……ちゃんと集まってる。","ENG":"Mm... I think everyone is here... from the elementary students to the high school students.","TWN":"嗯……從小學部到高中部……都到齊了呢。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"코스튬 기능도…… 잘 이용하고 있어……","JPN":"コスチューム機能も……使ってくれてる。","ENG":"They're all using... the costume system well...","TWN":"服裝功能……也都用上了……"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"너무 긴장하지 마 보라야.","JPN":"あまり緊張しないで、シホちゃん。","ENG":"Don't be too nervous, Bora.","TWN":"不要太緊張，寶拉。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"편하게 해도 돼. 그게 보라답잖아?","JPN":"少し肩の力を抜いたら？　そのほうがシホちゃんらしい。","ENG":"You can take it easy. That'll be more like you, don't you think?","TWN":"放輕鬆一點沒關係的，這才像你嘛，寶拉。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"응……. 고마워.","JPN":"うん……ありがとう。","ENG":"Okay... Thanks.","TWN":"嗯……謝謝你。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"시작할게……. 수업.","JPN":"じゃあ、始めるね……授業。","ENG":"Then I'll start... the class.","TWN":"開始上課吧。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_MAGICIAN_NPC_NULL","text":{"KOREA":"우와~ 두 분 모두 엄청난 복장으로 오셨잖아?","JPN":"わあ～2人ともすごいコスチューム！","ENG":"Wow! Both of your outfits are amazing!","TWN":"哇～你們倆都穿得好華麗啊！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"오늘 수업은 카운터즈 레거시를 자유롭게 탐험하는 것.","JPN":"今日の授業は、カウンターズ・レガシーを自由に探検すること。","ENG":"Today's class is freely exploring Counters Legacy.","TWN":"今天的課程是自由探索制裁者的遺產。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"하지만…… 조심해.","JPN":"でも……気をつけて。","ENG":"But... be careful.","TWN":"不過……一定要小心。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"튀어나올 수 있어…… 몬스터…… 어디서든.","JPN":"現れる……モンスター……いつでも。","ENG":"Monsters... might pop out... from anywhere.","TWN":"怪物可能會突然出現……無論從哪裡都有可能。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"이면 세계를 구현한 거니까……. 긴장을 늦추면 안 돼.","JPN":"裏世界を具現化しているから……気を抜かないように。","ENG":"This is a recreation of the Counterside... so don't let your guard down.","TWN":"因為是模擬了異界……不能掉以輕心。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"파티를 정해줄게……. 지금부터.","JPN":"パーティーを決める……今から。","ENG":"I'll assign all of you to parties... right now.","TWN":"從現在開始……我會安排組隊。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아하하. 랜덤으로 조를 정해주셨는데 같은 파티가 돼서 다행이야.","JPN":"あはは、ランダムで決めたのに同じパーティーになってよかった。","ENG":"Ah hah hah. I'm glad we all ended up in the same party, even though she randomly assigned all of us.","TWN":"哈哈哈。隨機分組後能和你在同一個隊伍真是太好了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그럼 뭐부터 해볼까?","JPN":"じゃあ、何からしようかな？","ENG":"Then, what shall we do first?","TWN":"那我們先做什麼呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"보라 선생님 말로는 여기서 여러 동물을 볼 수 있을 거라고 하셨어.","JPN":"先生の話だと、ここでは色んな動物が見れるらしいですね。","ENG":"Ms. Jin said that we could see a variety of animals here.","TWN":"寶拉老師說在這裡可以看到很多動物。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"비록 데이터에 불과하긴 해도, 궁금하니까 한번 찾아보자!","JPN":"実物じゃなくてデータだけど、気になるから探してみましょう！","ENG":"They might just be data, but I'm curious to see them!","TWN":"雖然只是虛擬的，但還是很好奇，我們去找找看吧！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"혹시 이사장님은 저희랑 같은 파티가 되신 건가요?","JPN":"もしかして、理事長は僕たちと同じパーティーなんですか？","ENG":"Um, Ms. Chairwoman? Are you in the same party as us?","TWN":"難道理事長和我們是同一個隊的嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 그건 아니지만 오늘은 나도 수업에 참여할 의무가 있어.","JPN":"あはは、そうじゃなくて今日は私も授業に参加する義務があるの。","ENG":"Ah hah hah, not really. It's just a part of my job to participate in today's class.","TWN":"哈哈哈，那倒不是，但今天我也有義務參加課程。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"물론 방해하진 않을 테니까 너무 걱정하지 않아도 돼.","JPN":"邪魔にならないようにするから、心配はいらないわ。","ENG":"I won't disturb any of you, so don't worry.","TWN":"當然不會打擾你們，所以不用太擔心。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"그런 것 치곤, 엄청 본격적인 복장이신데……?","JPN":"その割にはすごく本格的なコスチュームですけど……","ENG":"You say that, but your outfit seems to be saying the opposite...","TWN":"話雖如此，你的裝扮還真是相當正式呢……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"너희들 그거 아니? 카운터즈 레거시는 동물을 볼 수 있는 것뿐만 아니라 키워볼 수도 있다는 거.","JPN":"ねえ、知ってる？　カウンターズ・レガシーでは、動物を見るだけじゃなくて育てることもできるの。","ENG":"Want to know something? In Counters Legacy, not only can you observe animals, but you can also raise them.","TWN":"你們知道嗎？制裁者的遺產不僅可以看到動物，還可以養動物喔。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"네?! 그게 가능해요?","JPN":"え！？　そんなことができるんですか？","ENG":"What?! That's possible?","TWN":"什麼？！真能養嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"물론이지. 내가 좋은 장소를 알고 있으니까 모두 잘 따라오렴.","JPN":"もちろん。いい場所を知っているから、ついてきて。","ENG":"Of course. I know a good place, so follow me.","TWN":"當然。我知道一個好地方，大家跟我來吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"앗, 소림아! 위험하잖아!","JPN":"あっ、ミズキ！　危険だよ！","ENG":"Ah, Sorim! Careful!","TWN":"啊，蕭林！太危險了吧！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};